UPDATE item_label SET valore = regexp_replace(valore, '(^|,)AB18(!?)(,|$)', '\1IN00\2\3', 'g') WHERE label = 'ABCLASSE' AND valore ~ '(^|,)AB18(!?)(,|$)';
