DO $$
DECLARE
    r RECORD;
BEGIN
    FOR r IN
        SELECT con.conname, rel.relname AS table_name
        FROM pg_constraint con
        JOIN pg_class rel ON rel.oid = con.conrelid
        JOIN pg_class frel ON frel.oid = con.confrelid
        WHERE con.contype = 'f'
          AND frel.relname = 'stats'
    LOOP
        EXECUTE format('ALTER TABLE %I ALTER CONSTRAINT %I DEFERRABLE INITIALLY IMMEDIATE', r.table_name, r.conname);
    END LOOP;
END $$;

SET CONSTRAINTS ALL DEFERRED;

UPDATE stats SET id = 'CO13' WHERE id = 'C012';
UPDATE stat_value SET stat_id = 'CO13' WHERE stat_id = 'C012';
