UPDATE item_label SET valore = regexp_replace(valore, '(^|,)C012(!?)(,|$)', '\1CO13\2\3', 'g') WHERE label = 'ABCLASSE' AND valore ~ '(^|,)C012(!?)(,|$)';

DELETE FROM modificatori WHERE id_stat = 'CD';
DELETE FROM stat_value WHERE stat_id = 'CD' OR mod = 'CD';
DELETE FROM stat_default WHERE stat_id = 'CD' OR default_mod = 'CD';
DELETE FROM stats WHERE id = 'CD';
